elements.content:
graph LR
  u[User] --> g[Gateway]
  g --> api[API Layer]
  api --> next[Next Step]

  classDef base fill:#171717,stroke:#525252,color:#ffffff,stroke-width:2px;
  classDef active fill:#6d28d9,stroke:#f97316,color:#ffffff,stroke-width:3px;
  classDef muted fill:#262626,stroke:#404040,color:#a3a3a3,stroke-width:1px;
  class u,g base;
  class api active;
  class next muted;

graph LR
  sys[System Context] --> asm[Assembled Prompt]
  msg[User Message] --> asm
  asm --> model[Claude Model]

  classDef base fill:#171717,stroke:#525252,color:#ffffff,stroke-width:2px;
  classDef active fill:#6d28d9,stroke:#f97316,color:#ffffff,stroke-width:3px;
  classDef muted fill:#262626,stroke:#404040,color:#a3a3a3,stroke-width:1px;
  class sys,msg base;
  class asm active;
  class model muted;

graph LR
  asm[Assembled Prompt] --> infer[Inference]
  infer --> tok[Output Tokens]
  tok --> reply[Model Reply]

  subgraph cm[Claude Model]
    infer
    tok
  end

  classDef base fill:#171717,stroke:#525252,color:#ffffff,stroke-width:2px;
  classDef active fill:#6d28d9,stroke:#f97316,color:#ffffff,stroke-width:3px;
  classDef muted fill:#262626,stroke:#404040,color:#a3a3a3,stroke-width:1px;
  class asm,reply muted;
  class infer,tok active;

graph RL
  model[Claude Model] --> api[API Layer]
  api --> fmt[Response Formatting]
  fmt --> g[Gateway]
  g --> u[User]

  classDef base fill:#171717,stroke:#525252,color:#ffffff,stroke-width:2px;
  classDef active fill:#6d28d9,stroke:#f97316,color:#ffffff,stroke-width:3px;
  classDef muted fill:#262626,stroke:#404040,color:#a3a3a3,stroke-width:1px;
  class model,g,u muted;
  class api,fmt active;
